ValidationRule.errorConditionFormula:
AND( NOT(ISBLANK(NIF__c)), OR( /* Regra Regex para Empresa: 9 dígitos E começa por 5, 6, 90, 91, 97, 98, 99 */ AND( RecordType.DeveloperName = "Business_Account", NOT(REGEX(NIF__c, "^(5[0-9]{8}|6[0-9]{8}|(90|91|97|98|99)[0-9]{7})$")) ),
/* Regra Regex para Cliente: Apenas 9 dígitos numéricos */ AND( RecordType.DeveloperName = "PersonAccount", NOT(REGEX(NIF__c, "^[0-9]{9}$")) ),
/* A Matemática do Módulo 11 (Aplica-se a ambos!) */ VALUE(MID(NIF__c, 9, 1)) <> IF( MOD( (VALUE(MID(NIF__c, 1, 1)) * 9) + (VALUE(MID(NIF__c, 2, 1)) * 8) + (VALUE(MID(NIF__c, 3, 1)) * 7) + (VALUE(MID(NIF__c, 4, 1)) * 6) + (VALUE(MID(NIF__c, 5, 1)) * 5) + (VALUE(MID(NIF__c, 6, 1)) * 4) + (VALUE(MID(NIF__c, 7, 1)) * 3) + (VALUE(MID(NIF__c, 8, 1)) * 2), 11 ) < 2, 0, 11 - MOD( (VALUE(MID(NIF__c, 1, 1)) * 9) + (VALUE(MID(NIF__c, 2, 1)) * 8) + (VALUE(MID(NIF__c, 3, 1)) * 7) + (VALUE(MID(NIF__c, 4, 1)) * 6) + (VALUE(MID(NIF__c, 5, 1)) * 5) + (VALUE(MID(NIF__c, 6, 1)) * 4) + (VALUE(MID(NIF__c, 7, 1)) * 3) + (VALUE(MID(NIF__c, 8, 1)) * 2), 11 ) ) ) )
